from flask import Flask, redirect, url_for, session, request, jsonify
import requests
import os
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Replace these values with your OAuth provider's details
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_BASE_URL = 'https://authserver.com/oauth/authorize'
TOKEN_URL = 'https://authserver.com/oauth/token'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/')
def home():
    return 'Welcome to the OAuth client application'

@app.route('/login')
def login():
    authorization_url = f"{AUTHORIZATION_BASE_URL}?{urlencode({'response_type': 'code', 'client_id': CLIENT_ID, 'redirect_uri': REDIRECT_URI})}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(TOKEN_URL, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })

    token_json = token_response.json()
    session['access_token'] = token_json['access_token']
    return jsonify(token_json)

if __name__ == '__main__':
    app.run(debug=True)